#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uTexSize.xy=uTexSize.zw*3;
vec2 muv=vUv;
//vUv=vUvOriginal;
vec3 lluu = GetPixel(vec2(vUv.x-uTexSize.x*2,vUv.y-uTexSize.y*2));
vec3 luu  = GetPixel(vec2(vUv.x-uTexSize.x,vUv.y-uTexSize.y*2));
vec3 lu   = GetPixel(vec2(vUv.x-uTexSize.x,vUv.y-uTexSize.y));
vec3 rruu = GetPixel(vec2(vUv.x+uTexSize.x*2,vUv.y-uTexSize.y*2));
vec3 ruu  = GetPixel(vec2(vUv.x+uTexSize.x,vUv.y-uTexSize.y*2));
vec3 ru   = GetPixel(vec2(vUv.x+uTexSize.x,vUv.y-uTexSize.y));
vec3 lldd = GetPixel(vec2(vUv.x-uTexSize.x*2,vUv.y+uTexSize.y*2));
vec3 ldd  = GetPixel(vec2(vUv.x-uTexSize.x,vUv.y+uTexSize.y*2));
vec3 ld   = GetPixel(vec2(vUv.x-uTexSize.x,vUv.y+uTexSize.y));
vec3 rrdd = GetPixel(vec2(vUv.x+uTexSize.x*2,vUv.y+uTexSize.y*2));
vec3 rdd  = GetPixel(vec2(vUv.x+uTexSize.x,vUv.y+uTexSize.y*2));
vec3 rd   = GetPixel(vec2(vUv.x+uTexSize.x,vUv.y+uTexSize.y));
//ret-=((lu+luu+lu)*(1-lluu))*0.1;
//uncomment upper - kinda new look.
ret+=1.2*(rd+rdd+rrdd+ld+ldd+lldd+ru+ruu+rruu+lu+lluu+luu)/12;
ret-=GetBlur1(vUv)*0.5;
ret/=1+(rd+ld+lu+ld)*0.01;
ret*=1.1;
//try
//ret+=0.05;
//instead of
ret+=0.1*(0.5-texture(sampler_noise_lq,vUvOriginal*rand_frame.xy*9));


  fragColor = ret;
}

